Each stage is a tagged-error Effect; Effect.gen threads them sequentially, so the first failure short-circuits. FS and Bucket are services so tests can substitute in-memory fakes via Layer.succeed.

```typescript
import { Effect, Data, Context, Layer } from "effect";

class ReadFailed extends Data.TaggedError("ReadFailed")<{ readonly path: string }> {}
class TooLarge extends Data.TaggedError("TooLarge")<{ readonly size: number }> {}
class StoreFailed extends Data.TaggedError("StoreFailed")<{ readonly key: string }> {}

interface FS { readonly read: (p: string) => Effect.Effect<Uint8Array, ReadFailed> }
interface Bucket { readonly put: (k: string, d: Uint8Array) => Effect.Effect<void, StoreFailed> }

const FS = Context.GenericTag<FS>("app/FS");
const Bucket = Context.GenericTag<Bucket>("app/Bucket");

const upload = (path: string, key: string) =>
  Effect.gen(function* () {
    const fs = yield* FS;
    const bucket = yield* Bucket;
    const raw = yield* fs.read(path);
    if (raw.length > 1_000_000) return yield* Effect.fail(new TooLarge({ size: raw.length }));
    const enc = raw.map((b) => b ^ 0xff);
    yield* bucket.put(key, enc);
    return { key, bytes: enc.length };
  });

const Live = Layer.mergeAll(
  Layer.succeed(FS, { read: () => Effect.succeed(new Uint8Array([1, 2, 3])) }),
  Layer.succeed(Bucket, { put: () => Effect.void }),
);

export const program = Effect.provide(upload("/in", "out"), Live);

