import { Effect, Queue, Fiber, Ref } from "effect";

interface Job { readonly id: string; readonly payload: string }

const workerLoop = (q: Queue.Queue<Job>, done: Ref.Ref<number>) =>
  Effect.gen(function* () {
    while (true) {
      const job = yield* Queue.take(q);
      yield* Effect.sync(() => console.log("processing", job.id));
      yield* Ref.update(done, (n) => n + 1);
    }
  });

export const run = Effect.gen(function* () {
  const q = yield* Queue.bounded<Job>(16);
  const done = yield* Ref.make(0);
  const fibers = yield* Effect.forEach(
    [0, 1, 2, 3],
    () => Effect.fork(workerLoop(q, done)),
  );
  yield* Queue.offer(q, { id: "a", payload: "x" });
  yield* Queue.offer(q, { id: "b", payload: "y" });
  // graceful shutdown: interrupt all worker fibers
  yield* Effect.forEach(fibers, (f) => Fiber.interrupt(f));
  return yield* Ref.get(done);
});

