import { Effect, Queue, Fiber, Ref, Data } from "effect";

interface Job { readonly id: string }
class JobFailed extends Data.TaggedError("JobFailed")<{ readonly id: string }> {}

const process = (j: Job): Effect.Effect<void, JobFailed> =>
  j.id === "bad" ? Effect.fail(new JobFailed({ id: j.id })) : Effect.void;

const worker = (q: Queue.Queue<Job>, shutdown: Ref.Ref<boolean>) =>
  Effect.gen(function* () {
    while (!(yield* Ref.get(shutdown))) {
      const j = yield* Queue.take(q);
      yield* Effect.catchTag(process(j), "JobFailed", (e) =>
        Effect.sync(() => console.error("job failed", e.id)),
      );
    }
  });

export const pool = Effect.gen(function* () {
  const q = yield* Queue.bounded<Job>(64);
  const shutdown = yield* Ref.make(false);
  const fibers = yield* Effect.forEach([1, 2, 3], () => Effect.fork(worker(q, shutdown)));
  yield* Queue.offerAll(q, [{ id: "a" }, { id: "b" }, { id: "bad" }]);
  yield* Ref.set(shutdown, true);
  yield* Effect.forEach(fibers, (f) => Fiber.interrupt(f));
});

