import { Effect, Queue, Fiber, Deferred } from "effect";

interface Task { readonly id: number; readonly work: string }

const worker = (q: Queue.Queue<Task>, stop: Deferred.Deferred<void>) =>
  Effect.gen(function* () {
    while (true) {
      const done = yield* Deferred.isDone(stop);
      if (done) return;
      const task = yield* Queue.take(q);
      yield* Effect.sync(() => console.log("worker handled", task.id));
    }
  });

export const run = Effect.gen(function* () {
  const q = yield* Queue.bounded<Task>(32);
  const stop = yield* Deferred.make<void>();
  const fibers = yield* Effect.forEach([1, 2], () => Effect.fork(worker(q, stop)));
  yield* Queue.offer(q, { id: 1, work: "a" });
  yield* Deferred.succeed(stop, undefined);
  yield* Effect.forEach(fibers, (f) => Fiber.interrupt(f));
});

