import { Effect, Queue, Fiber, Data } from "effect";

interface Job { readonly id: string; readonly value: number }
class WorkerCrashed extends Data.TaggedError("WorkerCrashed")<{ readonly id: string }> {}

const handle = (j: Job): Effect.Effect<number, WorkerCrashed> =>
  j.value < 0 ? Effect.fail(new WorkerCrashed({ id: j.id })) : Effect.succeed(j.value * 2);

const loop = (q: Queue.Queue<Job>) =>
  Effect.gen(function* () {
    while (true) {
      const j = yield* Queue.take(q);
      yield* Effect.catchTag(handle(j), "WorkerCrashed", () => Effect.void);
    }
  });

export const spawnPool = (size: number) =>
  Effect.gen(function* () {
    const q = yield* Queue.bounded<Job>(256);
    const fibers = yield* Effect.forEach(
      Array.from({ length: size }, (_, i) => i),
      () => Effect.fork(loop(q)),
    );
    return {
      submit: (j: Job) => Queue.offer(q, j),
      shutdown: () => Effect.forEach(fibers, (f) => Fiber.interrupt(f)),
    };
  });

