export const makeLimiter = (maxInFlight: number) =>
  Effect.gen(function* () {
    const sem = yield* Effect.makeSemaphore(maxInFlight);
    return <A, E, R>(eff: Effect.Effect<A, E, R>) => sem.withPermits(1)(eff);
