      return { result, elapsedMs: t1 - t0 };
    });
});

export const wrapped = Effect.gen(function* () {
  const limit = yield* rateLimit5;
  return yield* limit(
    pipe(
      Effect.succeed("ok"),
      Effect.tap((x) => Effect.sync(() => console.log("result:", x))),
    ),
  );
});

