import { Effect, Ref, Effect as E } from "effect";

type Sem = Effect.Semaphore;

export const makeKeyLimiter = (permits: number) =>
  Effect.gen(function* () {
    const store = yield* Ref.make(new Map<string, Sem>());
    const acquire = (key: string) =>
      Effect.gen(function* () {
        const map = yield* Ref.get(store);
        const existing = map.get(key);
        if (existing) return existing;
        const sem = yield* Effect.makeSemaphore(permits);
        yield* Ref.update(store, (m) => {
          const copy = new Map(m);
          copy.set(key, sem);
          return copy;
        });
        return sem;
      });
    return <A, E2, R>(key: string, eff: Effect.Effect<A, E2, R>) =>
      Effect.gen(function* () {
        const sem = yield* acquire(key);
        return yield* sem.withPermits(1)(eff);
      });
  });

