import { Effect, Ref, Fiber } from "effect";

interface Row { readonly id: number; readonly count: number }

const fetchReal = (id: number): Effect.Effect<Row> => Effect.succeed({ id, count: 42 });

export const optimisticIncrement = (current: Row) =>
  Effect.gen(function* () {
    const view = yield* Ref.make<Row>({ ...current, count: current.count + 1 });
    const fiber = yield* Effect.fork(fetchReal(current.id));
    const real = yield* Fiber.join(fiber);
    yield* Ref.set(view, real);
    return yield* Ref.get(view);
  });

```

The speculative value goes into a Ref immediately so the UI renders without waiting. Effect.fork runs the real request in the background; Effect.either lets us observe success vs failure without throwing, and the Ref is either updated with the server value or rolled back.

