import { Effect, Ref, Fiber, Data } from "effect";

interface Like { readonly postId: string; readonly count: number }
class LikeFailed extends Data.TaggedError("LikeFailed")<{ readonly postId: string }> {}

const apiLike = (postId: string): Effect.Effect<Like, LikeFailed> =>
  Effect.succeed({ postId, count: 10 });

export const like = (current: Like) =>
  Effect.gen(function* () {
    const view = yield* Ref.make<Like>({ ...current, count: current.count + 1 });
    const fiber = yield* Effect.fork(apiLike(current.postId));
    const result = yield* Effect.either(Fiber.join(fiber));
    if (result._tag === "Left") {
      yield* Ref.set(view, current); // rollback
    } else {
      yield* Ref.set(view, result.right);
    }
    return yield* Ref.get(view);
  });

