import { Effect, Ref, Data } from "effect";

interface Cart { readonly items: ReadonlyArray<string> }
class AddFailed extends Data.TaggedError("AddFailed")<{ readonly sku: string }> {}

const apiAdd = (cart: Cart, sku: string): Effect.Effect<Cart, AddFailed> =>
  sku === "bad" ? Effect.fail(new AddFailed({ sku })) : Effect.succeed({ items: [...cart.items, sku] });

export const optimisticAdd = (view: Ref.Ref<Cart>, sku: string) =>
  Effect.gen(function* () {
    const prev = yield* Ref.get(view);
    yield* Ref.set(view, { items: [...prev.items, sku] });
    const result = yield* Effect.either(apiAdd(prev, sku));
    if (result._tag === "Left") {
      yield* Ref.set(view, prev);
      return { ok: false as const, error: result.left };
    }
    yield* Ref.set(view, result.right);
    return { ok: true as const };
  });

