class ApiError extends Data.TaggedError("ApiError")<{ readonly id: string }> {}

const api = (m: Model): Effect.Effect<Model, ApiError> =>
  m.id === "bad" ? Effect.fail(new ApiError({ id: m.id })) : Effect.succeed({ ...m, count: m.count + 1 });

